parameters.jsCode:
// Determine lookback period (3 days on Monday, 1 day otherwise)
const today = new Date();
const dayOfWeek = today.getDay(); // 0=Sun, 1=Mon, ...
const isMonday = dayOfWeek === 1;
const lookbackDays = isMonday ? 3 : 1;

return [{
  json: {
    standupId: `standup-${today.toISOString().split('T')[0]}`,
    date: today.toISOString().split('T')[0],
    lookbackDays,
    isMonday,
    idempotencyKey: `standup:${today.toISOString().split('T')[0]}`
  }
}];

